import React, { useEffect, useState } from 'react';
import { Link, Outlet } from 'react-router-dom';
import axios from 'axios';
import { Bar } from 'react-chartjs-2';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
} from 'chart.js';

ChartJS.register(CategoryScale, LinearScale, BarElement, Title, Tooltip, Legend);

function Dashboard({ token, logout }) {
  const [stats, setStats] = useState({});

  useEffect(() => {
    axios.defaults.headers.common['Authorization'] = `Bearer ${token}`;
    loadStats();
  }, [token]);

  const loadStats = async () => {
    try {
      const [{ data: exams }] = await Promise.all([
        axios.get('/admin/exams').catch(() => []),
        axios.get('/admin/orders').catch(() => [])
      ]);
      setStats({
        totalExams: exams.length,
        totalOrders: 0, // Add orders count
        pendingOrders: 0
      });
    } catch {}
  };

  const data = {
    labels: ['Exams', 'Orders', 'Downloads'],
    datasets: [{
      label: 'Count',
      data: [stats.totalExams || 0, 0, 0],
      backgroundColor: 'rgba(75,192,192,0.6)',
    }],
  };

  return (
    <div className="d-flex min-vh-100 bg-light">
      <div className="bg-dark text-white sidebar" style={{width: '250px'}}>
        <div className="p-3 border-bottom">
          <h4>Vyntex Admin</h4>
        </div>
        <nav className="nav flex-column p-3">
          <Link className="nav-link text-white" to="/dashboard"><i className="bi bi-house me-2"></i>Overview</Link>
          <Link className="nav-link text-white" to="/exams"><i className="bi bi-book me-2"></i>Exams</Link>
          <Link className="nav-link text-white" to="/orders"><i className="bi bi-receipt me-2"></i>Orders</Link>
          <hr />
          <button className="btn btn-outline-light w-100" onClick={logout}>Logout</button>
        </nav>
      </div>
      <main className="flex-grow-1 p-4">
        <div className="row mb-4">
          <div className="col-md-3">
            <div className="card text-center">
              <div className="card-body">
                <h5>{stats.totalExams || 0}</h5>
                <p>Total Exams</p>
              </div>
            </div>
          </div>
        </div>
        <div className="card">
          <div className="card-body">
            <h5>Overview Chart</h5>
            <Bar data={data} />
          </div>
        </div>
      </main>
    </div>
  );
}

export default Dashboard;
